SELECT DISTINCT r.room_name
FROM crops c
JOIN rooms r ON c.room_id = r.room_id;

SELECT room_name, temperature
FROM rooms
WHERE temperature = (SELECT MAX(temperature) FROM rooms);

SELECT room_name, AVG(temperature) AS avg_temperature, AVG(humidity) AS avg_humidity
FROM rooms
WHERE room_id = 1;

SELECT AVG(temperature), AVG(humidity)
FROM rooms
WHERE room_id = 0;

SELECT room_name
FROM rooms
WHERE temperature = (SELECT MAX(temperature) FROM rooms) AND light_exposure > 9500;
